    76→
    77→  it("skips ingredient lines", () => {
    78→    expect(extractTitle("2 cups flour\nApple Pie")).toBe("Apple Pie");
    79→  });
    80→
    81→  it("skips all-caps lines", () => {
    82→    expect(extractTitle("INGREDIENTS\nChocolate Cake")).toBe("Chocolate Cake");
    83→  });
    84→
    85→  it("skips lines starting with numbers", () => {
    86→    expect(extractTitle("12\nApple Pie")).toBe("Apple Pie");
    87→  });
    88→});
    89→
    90→describe("extractTitleWithEmbeddings", () => {
    91→  beforeEach(() => {
    92→    _resetEmbeddingCacheForTests();
    93→  });
    94→
    95→  it("returns undefined for empty text", async () => {
