    97→    expect(await extractTitleWithEmbeddings("", embed)).toBeUndefined();
    98→    expect(await extractTitleWithEmbeddings("  ", embed)).toBeUndefined();
    99→  });
   100→
   101→  it("picks title over section header (Polish)", async () => {
   102→    const embed = createMockEmbed(["pierogi ruskie"], ["składniki"]);
   103→    const text = "Składniki\nPierogi Ruskie\n200g mąki\n3 ziemniaki";
