  if (!cachedHeaderRefEmbedding) {
    cachedHeaderRefEmbedding = await embed(HEADER_REFERENCE);
  }
  if (!cachedNoiseRefEmbedding) {
    cachedNoiseRefEmbedding = await embed(NOISE_REFERENCE);
  }

  // Find the first ALL_CAPS candidate with ≥2 words where every word has ≥4 alpha letters.
  // This structural signal identifies the first clean recipe title heading in cookbook scans.
  const firstStructuralHeading = candidates.find(
    (c) =>
      isAllCaps(c.text) &&
      wordCount(c.text) >= 2 &&
      c.text
        .trim()
        .split(/\s+/)
        .every((w) => w.replace(/[^A-Z]/g, "").length >= 4)
